// Evaluate website response and determine status
const items = $input.all();
const results = [];

for (const item of items) {
  const statusCode = item.json.statusCode || 0;
  const responseTime = item.json.responseTime || 0;
  const headers = item.json.headers || {};
  const error = item.json.error || null;

  let status = 'up';
  let issue = '';

  if (statusCode === 0 || error) {
    status = 'down';
    issue = error ? `Connection error: ${error.message || error}` : 'No response received';
  } else if (statusCode >= 500) {
    status = 'down';
    issue = `Server error: HTTP ${statusCode}`;
  } else if (statusCode >= 400) {
    status = 'degraded';
    issue = `Client error: HTTP ${statusCode}`;
  } else if (responseTime > 3000) {
    status = 'slow';
    issue = `Response time ${responseTime}ms exceeds 3000ms threshold`;
  }

  results.push({
    json: {
      url: 'https://example.com',
      statusCode,
      responseTime,
      status,
      issue,
      checkedAt: new Date().toISOString(),
      needsAlert: status === 'down' || status === 'degraded'
    }
  });
}

return results;

